#include <bits/stdc++.h>
using namespace std;
int n,a[11],sum=0;
queue<int> b[11];
void dfs(int x,int rest){
	if(x>10){
		sum++;
		for(int i=1;i<=10;i++)
			b[i].push(a[i]);
	}else{
		for(int i=1;i<=3;i++)
			if(rest-i>=10-x && rest-i<=(10-x)*3){
				a[x]=i;
				dfs(x+1,rest-i);
			}
	}
}
int main(){
	cin>>n;
	dfs(1,n);
	cout<<sum;
	for(int i=1;i<=sum;i++){
		cout<<endl;
		for(int j=1;j<=10;j++){
			cout<<b[j].front()<<' ';
			b[j].pop();
		}
	}
	return 0;
}
